from dataclasses import dataclass
from datetime import date

@dataclass
class DailyTriageItem:
    bug_id: str
    current_priority: str           # "P2" expected; may have changed since filing
    filed_scope: str                # scope from initial report
    log_validated_scope: str | None # scope after log analysis; None if not yet done
    log_affected_requests_per_day: int | None
    days_since_filed: int
    fix_status: str                 # "not started", "assigned", "in progress", "blocked"
    blocker: str | None

    def should_promote(self) -> bool:
        # Promote P2 → P1 if log-validated scope is wider than filed scope
        if self.log_validated_scope is None:
            return False
        wider = {
            "single_customer": ["subset_of_users", "enterprise_only", "all_customers"],
            "subset_of_users": ["enterprise_only", "all_customers"],
            "enterprise_only":  ["all_customers"],
        }
        return self.log_validated_scope in wider.get(self.filed_scope, [])

    def is_stale(self) -> bool:
        # P2 bug with no progress after 72h is stale
        return self.days_since_filed >= 3 and self.fix_status == "not started"

def run_daily_triage(items: list[DailyTriageItem]) -> dict:
    promote = [i for i in items if i.should_promote()]
    stale   = [i for i in items if i.is_stale()]
    blocked = [i for i in items if i.blocker]
    return {
        "promote_to_p1": [i.bug_id for i in promote],
        "stale_need_owner": [i.bug_id for i in stale],
        "blocked_need_escalation": [(i.bug_id, i.blocker) for i in blocked],
    }

from dataclasses import dataclass
from datetime import datetime

@dataclass
class IncidentTriageState:
    incident_id: str
    incident_start: datetime
    incident_resolved_at: datetime | None

    def triage_suspended(self) -> bool:
        return self.incident_resolved_at is None

    def catchup_deadline(self) -> datetime | None:
        if self.incident_resolved_at is None:
            return None
        from datetime import timedelta
        return self.incident_resolved_at + timedelta(hours=48)

def post_incident_bug_review(
    bugs_filed_during_incident: list[dict],
    incident_root_cause: str,
) -> dict:
    """
    Classify bugs filed during an incident into those addressed by the RCA fix
    and those that are independent issues requiring separate triage.
    Returns a report for the post-incident triage catch-up session.
    """
    likely_symptoms = []
    independent_bugs = []

    for bug in bugs_filed_during_incident:
        # Heuristic: if the bug was filed within 2h of incident start
        # and the description overlaps with the incident, treat as symptom
        overlap_signals = [
            s for s in [incident_root_cause.lower()]
            if any(word in bug.get("title", "").lower() for word in s.split())
        ]
        if overlap_signals:
            likely_symptoms.append(bug["bug_id"])
        else:
            independent_bugs.append(bug["bug_id"])

    return {
        "likely_symptoms_close_after_fix_validated": likely_symptoms,
        "independent_need_triage": independent_bugs,
    }
